noncompliant:
void doSomething(int& a);
void f() {
  int* ptr = nullptr;
  doSomething(*ptr); // Noncompliant - dereferencing null pointer
}

void process(MyClass& obj);
void g() {
  MyClass* obj = nullptr;
  process(*obj); // Noncompliant - binding null dereference to reference
}

compliant:
void doSomething(int& a);
void f() {
  int value = 42;
  int* ptr = &value;
  if (ptr != nullptr) {
    doSomething(*ptr); // Compliant - checked for null
  }
}

void process(MyClass& obj);
void g() {
  MyClass obj;
  process(obj); // Compliant - direct object reference
}
